import torch


def resume_training_from_checkpoint(checkpoint_path: str) -> dict:
    try:
        # Load the checkpoint from the specified path with weights_only=True for security
        checkpoint = torch.load(checkpoint_path, weights_only=True)

        # Verify the checkpoint contains required training states
        if "model_state_dict" not in checkpoint or "optimizer_state_dict" not in checkpoint:
            # Check if the checkpoint is a model state dict directly (all values are tensors)
            if isinstance(checkpoint, dict) and all(isinstance(v, torch.Tensor) for v in checkpoint.values()):
                # If it's a model state dict, wrap it in the expected format with dummy optimizer state
                checkpoint = {
                    "model_state_dict": checkpoint,
                    "optimizer_state_dict": {},
                    "epoch": 0,
                    "loss": 0.0
                }
            else:
                raise ValueError("Checkpoint file missing required keys: 'model_state_dict' or 'optimizer_state_dict'")

        return checkpoint
    except FileNotFoundError:
        raise FileNotFoundError(f"Checkpoint file not found at: {checkpoint_path}")
    except Exception as e:
        raise RuntimeError(f"Failed to load checkpoint from {checkpoint_path}: {str(e)}")
